const Logo=({s=48,c=WH})=><span style={{fontFamily:"'Brush Script MT','Segoe Script','Apple Chancery',cursive",fontSize:s,color:c,lineHeight:1}}>felp.</span>;

// Animated handwriting logo for start screen
function AnimLogo({s=80}){
  const [vis,setVis]=useState(0);
  const letters="felp.";
  useEffect(()=>{
    const t=setTimeout(()=>{
      let i=0;
      const iv=setInterval(()=>{i++;setVis(i);if(i>=letters.length)clearInterval(iv);},180);
      return()=>clearInterval(iv);
    },400);
    return()=>clearTimeout(t);
  },[]);
  return(
    <span style={{fontFamily:"'Brush Script MT','Segoe Script','Apple Chancery',cursive",fontSize:s,color:WH,lineHeight:1,display:"inline-block"}}>
      {letters.split("").map((ch,i)=>(
        <span key={i} style={{
          display:"inline-block",
          opacity:i<vis?1:0,
          transform:i<vis?"translateY(0) rotate(0deg)":"translateY(12px) rotate(-8deg)",
          transition:"all 0.4s cubic-bezier(0.34,1.56,0.64,1)",
          transitionDelay:`${i*0.05}s`,
        }}>{ch}</span>
      ))}
    </span>
  );
}

