// ═══════════════════════════════════════════════════════════════
// S2: INSPIRATION — full bleed, touch swipe like Tinder
// ═══════════════════════════════════════════════════════════════
function S2({rests,onGo}){
  const [i,setI]=useState(0);
  const [offset,setOffset]=useState(0);
  const [swiping,setSwiping]=useState(false);
  const [gone,setGone]=useState(null); // "left" | "right" | null
  const startX=useRef(0);
  const dragging=useRef(false);

  const r=rests[i%rests.length];
  const next=rests[(i+1)%rests.length];

  const onTouchStart=e=>{startX.current=e.touches[0].clientX;dragging.current=true;setSwiping(true);};
  const onTouchMove=e=>{if(!dragging.current)return;const dx=e.touches[0].clientX-startX.current;setOffset(dx);};
  const onTouchEnd=()=>{
    dragging.current=false;setSwiping(false);
    if(Math.abs(offset)>80){
      const dir=offset>0?"right":"left";
      setGone(dir);
      setTimeout(()=>{setI(x=>x+1);setOffset(0);setGone(null);},300);
    } else {setOffset(0);}
  };
  const onMouseDown=e=>{startX.current=e.clientX;dragging.current=true;setSwiping(true);};
  const onMouseMove=e=>{if(!dragging.current)return;const dx=e.clientX-startX.current;setOffset(dx);};
  const onMouseUp=()=>{onTouchEnd();};

  const swBtn=d=>{
    setGone(d);
    setTimeout(()=>{setI(x=>x+1);setOffset(0);setGone(null);},300);
  };

  // Calculate transform based on drag
  const rot=offset*0.08;
  const tx=gone==="left"?"-120%":gone==="right"?"120%":`${offset}px`;
  const tr=gone==="left"?"-15deg":gone==="right"?"15deg":`${rot}deg`;
  const op=Math.max(0.3,1-Math.abs(offset)/400);

  return(
    <div style={{height:"100%",position:"relative",overflow:"hidden",background:"#1a0a12"}}>
      {/* Next card behind */}
      <img src={next.im} alt="" style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",opacity:0.4}}/>

      {/* Current card - draggable */}
      <div
        onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}
        onMouseDown={onMouseDown} onMouseMove={onMouseMove} onMouseUp={onMouseUp} onMouseLeave={()=>{if(dragging.current)onMouseUp();}}
        style={{
          position:"absolute",inset:0,
          transform:`translateX(${tx}) rotate(${tr})`,
          transition:gone||!swiping?"transform 0.3s cubic-bezier(0.16,1,0.3,1)":"none",
          cursor:"grab",userSelect:"none",WebkitUserSelect:"none",touchAction:"pan-y",
        }}
      >
        <img src={r.im} alt="" style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",pointerEvents:"none"}}/>
        <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom, rgba(139,26,74,0.7) 0%, transparent 20%, transparent 50%, rgba(0,0,0,0.65) 100%)",pointerEvents:"none"}}/>

        {/* Like / Nope indicators */}
        {offset>40&&<div style={{position:"absolute",top:100,left:24,padding:"8px 20px",borderRadius:8,border:"3px solid #4CAF50",color:"#4CAF50",fontSize:24,fontWeight:800,transform:"rotate(-15deg)",opacity:Math.min(1,(offset-40)/60),zIndex:5}}>LIKE</div>}
        {offset<-40&&<div style={{position:"absolute",top:100,right:24,padding:"8px 20px",borderRadius:8,border:"3px solid #f44336",color:"#f44336",fontSize:24,fontWeight:800,transform:"rotate(15deg)",opacity:Math.min(1,(-offset-40)/60),zIndex:5}}>NOPE</div>}
      </div>

      {/* Header overlay */}
      <div style={{position:"absolute",top:0,left:0,right:0,padding:"54px 24px 0",zIndex:10,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div style={{pointerEvents:"none"}}><Logo s={28}/></div>
        <button onClick={onGo} style={{padding:"7px 16px",borderRadius:16,background:"rgba(255,255,255,0.18)",border:"1px solid rgba(255,255,255,0.25)",color:WH,fontSize:11,fontWeight:600,cursor:"pointer",backdropFilter:"blur(8px)",WebkitBackdropFilter:"blur(8px)"}}>Browse all →</button>
      </div>

      {/* Bottom content overlay */}
      <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"0 24px 28px",zIndex:10,pointerEvents:"none"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end",marginBottom:6}}>
          <div>
            <h2 style={{color:WH,fontSize:22,fontWeight:700,margin:0,textShadow:"0 1px 4px rgba(0,0,0,0.3)"}}>{r.ds[0].n}</h2>
            <p style={{color:"rgba(255,255,255,0.8)",fontSize:13,margin:"2px 0",fontWeight:500}}>{r.nm}</p>
          </div>
          <div style={{display:"flex",alignItems:"center",gap:6}}>
            <div style={{width:28,height:28,borderRadius:"50%",border:"2px solid rgba(255,255,255,0.5)",display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:WH,fontSize:14}}>✓</span></div>
            <span style={{color:WH,fontSize:16,fontWeight:700}}>{r.mt}%</span>
          </div>
        </div>
        <p style={{color:"rgba(255,255,255,0.55)",fontSize:12,marginBottom:20}}>{r.cu} · {r.dist} · {r.pr}</p>
        <div style={{display:"flex",justifyContent:"center",gap:20,pointerEvents:"auto"}}>
          <button onClick={()=>swBtn("right")} style={{width:54,height:54,borderRadius:"50%",background:"transparent",border:"2px solid rgba(255,255,255,0.4)",fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"#f48fb1"}}>❤️</button>
          <button onClick={()=>swBtn("right")} style={{width:54,height:54,borderRadius:"50%",background:"transparent",border:"2px solid rgba(255,255,255,0.4)",fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:WH}}>⭐</button>
          <button onClick={()=>swBtn("left")} style={{width:54,height:54,borderRadius:"50%",background:"transparent",border:"2px solid rgba(255,255,255,0.4)",fontSize:20,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:"rgba(255,255,255,0.5)"}}>✕</button>
        </div>
      </div>
    </div>
  );
}

